class _JsonFileStore:
    """Minimal AsyncKeyValue store that persists tokens as JSON files in a directory.

    Avoids FileTreeStore's limitation of using keys as filesystem paths, which
    breaks when keys are URLs containing slashes.
    """

    def __init__(self, path: Path) -> None:
        self._path = path
        self._path.mkdir(parents=True, exist_ok=True)

    def _file(self, collection: str) -> Path:
        safe = hashlib.sha256(collection.encode()).hexdigest()[:16]
        return self._path / f"{safe}.json"

    def _load(self, collection: str) -> dict:
        f = self._file(collection)
        return json.loads(f.read_text()) if f.exists() else {}

    def _save(self, collection: str, data: dict) -> None:
        self._file(collection).write_text(json.dumps(data))

    async def get(self, key: str, *, collection: str | None = None) -> dict[str, Any] | None:
        return self._load(collection or "default").get(key)

    async def ttl(self, key: str, *, collection: str | None = None) -> tuple[dict[str, Any] | None, float | None]:
        return self._load(collection or "default").get(key), None

    async def put(self, key: str, value: Mapping[str, Any], *, collection: str | None = None, ttl: Any = None) -> None:
        data = self._load(collection or "default")
        data[key] = dict(value)
        self._save(collection or "default", data)

    async def delete(self, key: str, *, collection: str | None = None) -> bool:
        data = self._load(collection or "default")
        if key in data:
            del data[key]
            self._save(collection or "default", data)
            return True
        return False

    async def get_many(self, keys: list[str], *, collection: str | None = None) -> list[dict[str, Any] | None]:
        data = self._load(collection or "default")
        return [data.get(k) for k in keys]



def _keyring_get(account: str) -> str | None:
    try:
        import keyring as kr
        val = kr.get_password("atlan-mcp", account)
        if val is not None:
            return val
    except Exception:
        pass
    if _CREDS_FILE.exists():
        try:
            return json.loads(_CREDS_FILE.read_text()).get(account)
        except Exception:
            pass
    return None


def _keyring_set(account: str, value: str) -> None:
    try:
        import keyring as kr
        kr.set_password("atlan-mcp", account, value)
        return
    except Exception:
        pass
    _ATLAN_DIR.mkdir(parents=True, exist_ok=True)
    data: dict = {}
    if _CREDS_FILE.exists():
        try:
            data = json.loads(_CREDS_FILE.read_text())
        except Exception:
            pass
    data[account] = value
    _CREDS_FILE.write_text(json.dumps(data))
    _CREDS_FILE.chmod(0o600)


def _keyring_delete(account: str) -> None:
    try:
        import keyring as kr
        kr.delete_password("atlan-mcp", account)
    except Exception:
        pass
    if _CREDS_FILE.exists():
        try:
            data = json.loads(_CREDS_FILE.read_text())
            data.pop(account, None)
            _CREDS_FILE.write_text(json.dumps(data))
        except Exception:
            pass


def _maybe_json(v):
    """Parse v as JSON if it's a string; return v unchanged on failure."""
    if not isinstance(v, str):
        return v
    try:
        return json.loads(v)
    except (json.JSONDecodeError, ValueError):
        return v

def _read_config() -> dict | None:
    if not _CONFIG_FILE.exists():
        return None
    try:
        return json.loads(_CONFIG_FILE.read_text())
    except Exception:
        _stderr.print("[bold red]Error:[/bold red] Malformed ~/.atlan/config.json. Run [cyan]atlan login[/cyan].")
        sys.exit(3)


def _write_config(cfg: dict) -> None:
    _ATLAN_DIR.mkdir(parents=True, exist_ok=True)
    _CONFIG_FILE.write_text(json.dumps(cfg, indent=2))
    _CONFIG_FILE.chmod(0o600)


def _wipe_credentials() -> None:
    """Wipe all stored credentials. Called ONLY from: refresh failure, logout, login."""
    global _resolved
    _resolved = None
    for account in ("refresh_token", "access_token", "api_key"):
        _keyring_delete(account)
    # Clear FastMCP's internal token cache so next login --oauth always opens browser.
    import shutil
    cache = _ATLAN_DIR / ".fastmcp-cache"
    if cache.exists():
        shutil.rmtree(cache)


_resolved: tuple[str, object] | None = None


def _resolve_auth() -> tuple[str, object]:
    global _resolved
    if _resolved is not None:
        return _resolved

    override_api_key = os.environ.get("_ATLAN_OVERRIDE_API_KEY")
    override_tenant = os.environ.get("_ATLAN_OVERRIDE_TENANT", "").rstrip("/")
    override_oauth = os.environ.get("_ATLAN_OVERRIDE_OAUTH") == "1"

    if override_api_key and override_tenant:
        _resolved = (f"{override_tenant}/mcp/api-key", BearerAuth(override_api_key))
        return _resolved

    if override_oauth:
        url = f"{_OAUTH_PROXY}/mcp"
        store = _JsonFileStore(_ATLAN_DIR / ".fastmcp-cache")
        _resolved = (url, OAuth(mcp_url=url, token_storage=store))
        return _resolved

    cfg = _read_config()

    if cfg is None:
        # Legacy env-var fallback for users who haven't run atlan login yet
        base_url = os.environ.get("ATLAN_BASE_URL", "").rstrip("/")
        if not base_url:
            _err("Not authenticated. Run [cyan]atlan login[/cyan].")
            sys.exit(2)
        api_key = os.environ.get("ATLAN_API_KEY")
        force_oauth = os.environ.get("ATLAN_AUTH", "").lower() == "oauth"
        if api_key and not force_oauth:
            _resolved = (f"{base_url}/mcp/api-key", BearerAuth(api_key))
        else:
            store = _JsonFileStore(_ATLAN_DIR / ".fastmcp-cache")
            url = f"{base_url}/mcp"
            _resolved = (url, OAuth(mcp_url=url, token_storage=store))
        return _resolved

    auth_mode = cfg.get("auth_mode")

    if auth_mode == "api-key":
        tenant = cfg.get("tenant", "").rstrip("/")
        if not tenant:
            _err("Config error: api-key mode requires tenant URL. Run [cyan]atlan login[/cyan].")
            sys.exit(3)
        api_key = _keyring_get("api_key")
        if not api_key:
            _err("Not authenticated. Run [cyan]atlan login[/cyan].")
            sys.exit(2)
        _resolved = (f"{tenant}/mcp/api-key", BearerAuth(api_key))
        return _resolved

    if auth_mode == "oauth":
        at_raw = _keyring_get("access_token")
        if at_raw:
            try:
                at_data = json.loads(at_raw)
                if time.time() < at_data.get("expires_at", 0):
                    _resolved = (f"{_OAUTH_PROXY}/mcp", BearerAuth(at_data["access_token"]))
                    return _resolved
            except Exception:
                pass

        refresh_token = _keyring_get("refresh_token")
        if not refresh_token:
            _err("Not authenticated. Run [cyan]atlan login[/cyan].")
            sys.exit(2)

        import httpx
        try:
            resp = httpx.post(
                f"{_OAUTH_PROXY}/oauth/token",
                data={
                    "grant_type": "refresh_token",
                    "refresh_token": refresh_token,
                    "client_id": cfg.get("client_id", "mcp-client"),
                    "client_secret": "placeholder",
                },
                headers={"Content-Type": "application/x-www-form-urlencoded"},
                timeout=10,
            )
        except Exception as exc:
            _err(f"Network error during token refresh: {exc}")
            sys.exit(2)

        if resp.status_code != 200:
            _wipe_credentials()
            _err("Session expired. Run [cyan]atlan login[/cyan].")
            sys.exit(2)

        data = resp.json()
        access_token = data["access_token"]
        expires_in = data.get("expires_in", 300)
        _keyring_set("access_token", json.dumps({
            "access_token": access_token,
            "expires_at": time.time() + expires_in - 30,
        }))
        if "refresh_token" in data:
            _keyring_set("refresh_token", data["refresh_token"])

        _resolved = (f"{_OAUTH_PROXY}/mcp", BearerAuth(access_token))
        return _resolved

    _err(f"Unknown auth_mode {auth_mode!r}. Run [cyan]atlan login[/cyan].")
    sys.exit(3)

def _client() -> "Client":
    url, auth = _resolve_auth()
    return Client(url, auth=auth)


app = cyclopts.App(name="atlan", help="CLI for Atlan MCP server")

console = Console()
_stderr = Console(stderr=True)


def _err(msg: str) -> None:
    _stderr.print(msg)


