def main() -> None:
    global _JSON_MODE

    args = sys.argv[1:]
    subcommand = next((a for a in args if not a.startswith("-")), None)
    is_login = subcommand == "login"

    new_args: list[str] = []
    i = 0
    while i < len(args):
        a = args[i]
        if a == "--oauth":
            os.environ["_ATLAN_OVERRIDE_OAUTH"] = "1"
            # Don't add to new_args — consume the flag globally
        elif a == "--json":
            _JSON_MODE = True
            # Don't add to new_args — consume globally
        elif a == "--api-key" and i + 1 < len(args) and not is_login:
            os.environ["_ATLAN_OVERRIDE_API_KEY"] = args[i + 1]
            i += 1  # skip value too
        elif a == "--tenant" and i + 1 < len(args) and not is_login:
            os.environ["_ATLAN_OVERRIDE_TENANT"] = args[i + 1]
            i += 1  # skip value too
        else:
            new_args.append(a)
        i += 1

    sys.argv = [sys.argv[0]] + new_args
    try:
        app()
    except SystemExit:
        raise
    except Exception as exc:
        _err(f"[bold red]Error:[/bold red] {exc}")
        sys.exit(1)


if __name__ == "__main__":
    main()
